// Obtener el body del webhook
const body = $input.first().json.body;

// Validar que el body exista
if (!body) {
  return [{
    json: {
      error: true,
      message: "No se recibió ningún dato. Envía un JSON con 'query' y 'sessionId'.",
      received: null
    }
  }];
}

// Validar query
if (!body.query || typeof body.query !== 'string' || body.query.trim() === '') {
  return [{
    json: {
      error: true,
      message: "El campo 'query' es obligatorio y debe contener una pregunta válida.",
      received: body
    }
  }];
}

// Validar sessionId (opcional pero recomendado)
if (!body.sessionId || typeof body.sessionId !== 'string' || body.sessionId.trim() === '') {
  return [{
    json: {
      error: true,
      message: "El campo 'sessionId' es obligatorio para mantener el historial de conversación.",
      received: body
    }
  }];
}

// Input válido
const query = body.query.trim();
const sessionId = body.sessionId.trim();

return [{
  json: {
    error: false,
    query: query,
    sessionId: sessionId,
    timestamp: new Date().toISOString()
  }
}];
